import React, { useState, useEffect } from 'react';
import { useCart } from '../context/CartContext';
import { getDealOfDay, imgUrl } from '../services/api';
import shampooImg from '../assets/images/shampoo.png';
import './DealOfDay.css';

function pad(n) { return String(n).padStart(2, '0'); }

export default function DealOfDay({ onAddedToCart }) {
  const { addToCart } = useCart();
  const [deal, setDeal] = useState(null);
  const [time, setTime] = useState({ days:0, hours:0, mins:0, secs:0 });

  useEffect(() => {
    getDealOfDay().then(res => setDeal(res.data)).catch(() => {});
  }, []);
  useEffect(() => {
    if (!deal) return;
    const target = new Date(deal.end_datetime);
    const calc = () => {
      const diff = Math.max(0, target - Date.now());
      setTime({
        days:  Math.floor(diff / 86400000),
        hours: Math.floor((diff % 86400000) / 3600000),
        mins:  Math.floor((diff % 3600000)  / 60000),
        secs:  Math.floor((diff % 60000)    / 1000),
      });
    };
    calc();
    const id = setInterval(calc, 1000);
    return () => clearInterval(id);
  }, [deal]);

  const p      = deal?.product;
  const img    = p ? (imgUrl(p.image) || shampooImg) : shampooImg;
  const name   = p?.name        || 'SHAMPOO, CONDITIONER & FACEWASH';
  const price  = p ? `$${parseFloat(p.price).toFixed(2)}`          : '$150.00';
  const oldPr  = p?.old_price ? `$${parseFloat(p.old_price).toFixed(2)}` : '$200.00';
  const desc   = p?.description || 'Lorem ipsum dolor sit amet consectetur.';
  const sold   = deal?.sold_count  || 20;
  const total  = deal?.total_stock || 60;
  const avail  = total - sold;
  const pct    = Math.round((sold / total) * 100);

  function handleAdd() {
    const product = p
      ? { id: p.id, img, name: p.name, price: p.price, cat: p.category_name || 'Electronics', desc: p.description }
      : { id: 'dod1', img: shampooImg, name, price: '150.00', cat: 'Cosmetics', desc };
    addToCart(product);
    onAddedToCart?.(product);
  }

  return (
    <section className="dod-section">
      <h2 className="dod-section-title">Deal of The Day</h2>
      <div className="dod-card">
        <div className="dod-img-wrap">
          <img src={img} alt={name} className="dod-img" />
        </div>
        <div className="dod-content">
          <div className="dod-stars">
            {[1,2,3,4,5].map(s => <span key={s} className={s<=3?'dod-star filled':'dod-star'}>★</span>)}
          </div>
          <h3 className="dod-name">{name}</h3>
          <p className="dod-desc">{desc}</p>
          <div className="dod-price-row">
            <span className="dod-price">{price}</span>
            <span className="dod-old">{oldPr}</span>
          </div>
          <button className="dod-btn" onClick={handleAdd}>ADD TO CART</button>
          <div className="dod-progress-row">
            <span className="dod-progress-label">ALREADY SOLD: <strong>{sold}</strong></span>
            <span className="dod-progress-label">AVAILABLE: <strong>{avail}</strong></span>
          </div>
          <div className="dod-bar-bg">
            <div className="dod-bar-fill" style={{ width: `${pct}%` }} />
          </div>
          <p className="dod-hurry">HURRY UP! OFFER ENDS IN:</p>
          <div className="dod-timer">
            {[{val:pad(time.days),unit:'Days'},{val:pad(time.hours),unit:'Hours'},{val:pad(time.mins),unit:'Min'},{val:pad(time.secs),unit:'Sec'}].map(({val,unit}) => (
              <div className="dod-timer-box" key={unit}>
                <div className="dod-timer-num-wrap"><span className="dod-timer-num">{val}</span></div>
                <span className="dod-timer-unit">{unit}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
